import{simplifyPathTokens,tokenisePath}from"../treeUtil";import deserialiseUBJSON from"./ubjson";import zlibParseNode,{ZlibRangeSymbol,ZlibStringEnumSymbol,ZlibValueSymbol}from"./zlibNodeParser";export function zlibParse(zlib){const payload=deserialiseUBJSON(zlib);if(payload.id!=="Synchronize"){console.warn("Unexpected zlib payload id",payload.id);return}return zlibParseNode(payload)}export default zlibParse;export function getZlibValue(node,key){const tokens=[...simplifyPathTokens(tokenisePath(key))];let cur=node;while(cur&&tokens.length>0){const next=tokens.shift();cur=cur[next]}cur=cur?.[ZlibValueSymbol]??cur;if(cur===undefined)return null;return cur}export function getZlibKeyData(node,key,{value=false,range=true,strings=true}={}){const tokens=[...simplifyPathTokens(tokenisePath(key))];let cur=node;while(cur&&tokens.length>0){const next=tokens.shift();cur=cur[next]}if(cur===undefined)return null;const result={};if(value&&node[ZlibValueSymbol])result.value=node[ZlibValueSymbol];if(range&&node[ZlibRangeSymbol])result.range=node[ZlibRangeSymbol];if(strings&&node[ZlibStringEnumSymbol])result.strings=node[ZlibStringEnumSymbol];return result}